"use strict";(self.webpackChunk_N_E=self.webpackChunk_N_E||[]).push([[60],{6060:function(D,u,i){i.d(u,{Ix:function(){return e},XY:function(){return t}});let e=[{code:"ESTA",name:"社交小太阳",emoji:"☀️",slogan:"走到哪都是C位担当！",description:"你家毛孩子简直就是狗狗界的社交天花板！无论是人还是狗，它都能三秒钟打成一片，尾巴摇得像小马达。它聪明又听话，学新技能特别快，带它出门简直就是行走的圈粉神器。公园里它是气氛组担当，家里它是开心果本果。有它在，生活永远不缺欢乐和阳光！",traits:["\uD83C\uDF1F 社交达人: 见人就亲，见狗就嗨，天生的社交恐怖分子","\uD83C\uDF93 学习小天才: 教三遍就会，握手坐下转圈圈样样精通","⚡ 永动机体质: 电量满格，玩一天都不带累的","\uD83D\uDC95 暖心小棉袄: 情绪感知力满分，你难过时它会主动来哄你"],tips:["多带它社交: 定期去狗狗公园，让它尽情交朋友","脑力+体力双消耗: 除了运动，还要玩益智玩具，不然会拆家","正向激励训练: 它很在意你的夸奖，多给 verbal praise","注意防晒: 活跃的它夏天容易中暑，避开正午遛狗","社交礼仪教育: 太热情有时会吓到怕狗的人，要教它冷静"],activities:["\uD83C\uDFC3 飞盘/敏捷训练","\uD83C\uDFAA 狗狗聚会/宠物嘉年华","\uD83E\uDDE9 嗅闻垫/益智玩具挑战"],quirks:["有时候太热情，会扑到人身上（其实是想给抱抱啦）","离开主人会有一点点分离焦虑，因为实在太爱你了"],color:"#FF9A56"},{code:"ESTG",name:"好奇探险家",emoji:"\uD83E\uDDED",slogan:"世界那么大，本汪想去闻闻！",description:"这是一只对世界永远充满好奇的毛孩子！每个角落都值得探索，每片树叶都值得闻闻。它憨厚可爱，有时候反应慢半拍，但那认真的小眼神让人心都化了。虽然不够机灵，但它听话又努力，你教它的它都会认真学。它是那种会跟着你到处冒险，永远不会喊累的最佳旅伴！",traits:["\uD83C\uDF0D 探索欲MAX: 出门就像开盲盒，到处都是新鲜事","\uD83D\uDC3B 憨厚小可爱: 偶尔有点迷糊，但特别真诚","\uD83E\uDD1D 自来熟: 跟谁都能玩到一起，没有心眼","\uD83D\uDCAA 耐力十足: 能走能跑，陪你徒步十公里没问题"],tips:["满足探索欲: 多换遛狗路线，让它闻个够（嗅闻是狗狗的阅读）","简单明确的指令: 憨厚的它适合简单直接的训练，别绕弯子","耐心重复: 学得慢但记得牢，多点耐心，它会给你惊喜","安全牵引: 好奇宝宝容易被东西吸引，出门务必牵好","充足运动: 活跃分子需要每天至少1-2小时户外活动"],activities:["\uD83E\uDD7E 徒步/登山","\uD83C\uDFD6️ 海滩撒欢","\uD83D\uDD0D 寻宝游戏（藏零食让它找）"],quirks:["有时候过于专注闻东西，叫它会装聋作哑","憨厚不代表不捣蛋，好奇心太旺盛会翻垃圾桶"],color:"#FF8C42"},{code:"ESFA",name:"人气小明星",emoji:"⭐",slogan:"躺着也能圈粉无数！",description:"你家这位是个天生的明星体质！性格超好、人见人爱，关键是还特别聪明，懂得用最省力的方式获得最大的关注。它不像活跃狗狗那样上蹿下跳，而是优雅地躺着，用可爱的眼神和适时的撒娇征服所有人。它是那种躺在咖啡店门口就能被路人撸一圈的躺赢选手，慵懒却不失魅力！",traits:["\uD83D\uDECB️ 优雅躺平: 能坐着绝不站着，能躺着绝不坐着","\uD83E\uDDE0 聪明机灵: 懂得用最少的努力换取最大的回报","\uD83D\uDC9D 人气王: 自带光环，到哪都有人想rua","\uD83C\uDFAD 演技派: 会用眼神和表情表达自己的需求"],tips:["控制体重: 慵懒体质容易发胖，要注意饮食控制","短而精的运动: 不需要高强度运动，但每天要鼓励它动一动","脑力游戏: 聪明但懒得动，益智玩具是最佳选择","社交时光: 带它去宠物友好场所，让它享受被关注","舒适环境: 给它准备软软的窝，它真的很爱睡觉"],activities:["☕ 宠物友好咖啡厅趴趴走","\uD83D\uDCF8 拍照打卡（它超配合）","\uD83E\uDDE9 慢节奏益智游戏"],quirks:["训练时需要零食诱惑，空口夸奖对它动力不足","有时候会假装听不见，选择性执行指令"],color:"#F1C40F"},{code:"ESFG",name:"温暖老好人",emoji:"\uD83E\uDDE3",slogan:"温柔是唯一的超能力。",description:"这是一只让人忍不住想抱抱的毛孩子！它性格温和、不急不躁，对谁都友好，从不会发脾气。它可能不是最聪明的，但它是最真诚的；可能不是最活泼的，但它是最靠谱的。它喜欢静静地陪着你，你工作时它在脚边打盹，你看电视时它靠在你身旁。它是那种会治愈你所有疲惫的存在。",traits:["\uD83E\uDDF8 温柔本柔: 从来不发脾气，对小孩和其他动物都超有耐心","\uD83C\uDF43 慢性子: 干啥都不着急，慢悠悠的很治愈","\uD83D\uDC93 无条件的爱: 不管你是开心还是难过，它都在","\uD83C\uDF08 正能量: 虽然慵懒，但看到你就会摇尾巴"],tips:["不要逼它运动: 它真的不喜欢剧烈运动，散步就好","温柔训练: 它敏感又听话，严厉批评会让它难过","规律作息: 憨厚的它喜欢固定的生活节奏","注意关节: 慵懒+容易胖，要注意关节健康","多陪伴: 它最想要的就是和你一起 lazy 的时光"],activities:["\uD83D\uDECB️ 沙发 cuddles 时光","\uD83C\uDF05 傍晚悠闲散步","\uD83C\uDFE0 居家陪伴（它最擅长）"],quirks:["有时候会反应慢半拍，叫它需要等一会儿","对新指令接受较慢，需要更多耐心"],color:"#E67E22"},{code:"EITA",name:"机智跟屁虫",emoji:"\uD83E\uDDAE",slogan:"聪明又忠心，寸步不离身！",description:"这是一只智商在线、忠心耿耿的小保镖！它聪明伶俐，学东西快得惊人，同时又对你百分百忠诚。虽然对陌生人保持警惕，但只要你在，它就是最勇敢的小卫士。它喜欢跟在你身边，你走到哪它跟到哪，像个贴心的小跟班。有它在，你既不会觉得孤单，又多了份安全感。",traits:["\uD83E\uDDE0 高智商: 能听懂话，甚至能察言观色","\uD83D\uDEE1️ 小保镖: 对外人警惕，会站在你和陌生人之间","\uD83D\uDC63 跟屁虫: 主人走到哪跟到哪，上厕所也要守着","⚡ 活力满满: 需要运动，但更会看场合"],tips:["建立信任: 让它知道什么情况是安全的，减少过度警惕","社会化训练: 多接触不同的人和环境，避免过分敏感","脑力+体力结合: 聪明又活跃，需要运动量也要动脑","给它任务: 喜欢有工作的感觉，可以教它拿东西、看家","渐进式独处: 太黏人，要慢慢练习独处能力"],activities:["\uD83C\uDFAF 护卫犬基础训练","\uD83C\uDFC3 随行跑步","\uD83E\uDDE0 复杂指令学习"],quirks:["对陌生人叫得比较凶（其实是在保护你）","太黏人，你上厕所它都要跟着"],color:"#3498DB"},{code:"EITG",name:"独立思想家",emoji:"\uD83C\uDF93",slogan:"我有我的节奏，但我依然爱你。",description:"这是一只有点矛盾又特别可爱的毛孩子！它外向喜欢探索，却又保持着一份警惕；它憨厚不那么机灵，却有自己的小想法。它不会盲目服从，而是会先思考这件事值不值得做。它像个小哲学家，对这个世界有自己的一套理解。虽然有时候固执，但它的真诚和独立让人着迷。",traits:["\uD83E\uDD14 有自己的想法: 不是不听话，是想先想一想","\uD83C\uDF0D 探索+谨慎: 好奇但不过头，懂得保护自己","\uD83D\uDC15 憨厚真诚: 没有心眼，喜欢你都写在脸上","⚖️ 平衡感好: 活跃但知道分寸"],tips:["尊重它的节奏: 不要强迫，说服比命令更有效","建立信任关系: 它只听信任的人的话","多样化探索: 满足它的好奇心，带它去新地方","简单重复训练: 憨厚需要重复，但不要急","安全社交: 警惕性高，要引导正确社交"],activities:["\uD83D\uDDFA️ 城市探索（新路线）","\uD83D\uDC15 和熟悉的朋友玩","\uD83C\uDFAF 自主性强的游戏"],quirks:["有时候太有主见，训练需要更多耐心","对新事物反应慢，需要时间适应"],color:"#4ECDC4"},{code:"EIFA",name:"慢性子暖男",emoji:"\uD83E\uDDE4",slogan:"慢慢爱你，细水长流。",description:"这是一只与众不同的毛孩子！它外向却不闹腾，聪明却不耍心眼，慵懒却又保持着对外界的警惕。它像一杯温热的茶，不刺激却暖人心脾。它懂得用最舒适的方式生活，也懂得如何在慵懒中保持警觉。它不是那种扑上来舔你的热情狗狗，而是静静地走到你身边，靠着你，用眼神说我在。",traits:["\uD83D\uDC22 慢生活家: 做什么都不慌不忙，有自己的节奏","\uD83E\uDDE0 聪明淡定: 脑子转得快，但身体懒得动","\uD83D\uDC40 观察者: 看似慵懒，其实在观察一切","\uD83D\uDC99 温柔守护: 不会大吵大闹，但会默默保护你"],tips:["不要催它: 它有自己的节奏，催它会焦虑","脑力优先: 聪明但懒，多玩脑力游戏少跑跳","安全空间: 警惕性让它需要有自己的安全角落","温和社交: 外向但不冲动，适合安静的社交环境","注意饮食: 慵懒体质要控制体重"],activities:["☕ 安静的陪伴时光","\uD83E\uDDE9 慢节奏益智玩具","\uD83C\uDF05 傍晚悠闲散步"],quirks:["对陌生人保持警惕，需要时间才能放下戒心","训练时需要更多耐心，它要先想明白"],color:"#9B59B6"},{code:"EIFG",name:"淡定观察家",emoji:"\uD83D\uDC41️",slogan:"看淡一切，只对你认真。",description:"这是一只仿佛看透世事的毛孩子！它不争不抢、不吵不闹，像个老先生一样淡定从容。它憨厚老实，虽然反应不快，但那份真诚让人感动。它对世界保持着一份警惕，却不会过分紧张；它喜欢安静，却也会对外面的世界投去好奇的目光。它是那种会让你慢下来、静下心来感受生活的存在。",traits:["\uD83E\uDDD8 佛系: 什么都不急，什么都看得开","\uD83D\uDC3B 憨厚老实: 没有坏心眼，单纯得像张白纸","\uD83D\uDC41️ 观察者: 喜欢静静地看，而不是参与","\uD83D\uDEE1️ 谨慎: 虽然顺从，但不会盲目信任"],tips:["不要强迫社交: 它更喜欢观察，不要逼它参与","稳定环境: 警惕+憨厚，需要安全、规律的生活","温柔引导: 学东西慢，但温柔耐心它会懂","适度运动: 虽然懒，但也要每天散步保持活力","给它观察点: 窗边的位置，让它可以看外面的世界"],activities:["\uD83E\uDE9F 窗边观察时间","\uD83D\uDEB6 安静的散步","\uD83C\uDFE0 居家陪伴"],quirks:["太佛系，有时候叫不动","对陌生人太警惕，需要长时间才能熟悉"],color:"#34495E"},{code:"ISTA",name:"害羞甜心",emoji:"\uD83D\uDC97",slogan:"慢热但深情，只对懂的人撒娇。",description:"这是一只外冷内热的毛孩子！它内向害羞，不会主动接近陌生人，但一旦熟悉了，它会是你最贴心的小伙伴。它聪明伶俐，虽然不善社交但学习能力强；它活泼好动，却只在自己信任的人面前释放天性。它需要时间来建立信任，但那份信任一旦建立，就是一辈子的依赖。",traits:["\uD83C\uDF38 害羞可爱: 对陌生人会躲，但熟了超级黏人","\uD83E\uDDE0 聪明内敛: 默默观察，学东西很快","⚡ 窝里横: 在熟悉环境活泼得像换了只狗","\uD83D\uDC95 深情专一: 只认你，你是它的全世界"],tips:["不要强迫社交: 给它时间，让它慢慢适应新环境","安全基地: 准备一个它可以躲藏的安全角落","正向鼓励: 害羞的它更需要你的鼓励","一对一互动: 不喜欢大场面，更喜欢和你独处","渐进式脱敏: 慢慢让它接触新事物，不要一步到位"],activities:["\uD83C\uDFE0 居家游戏","\uD83D\uDC6B 一对一的互动训练","\uD83C\uDF33 安静的小公园"],quirks:["见生人会躲，可能被人误会不友好","太依赖你，离开你会焦虑"],color:"#F8C471"},{code:"ISTG",name:"敏感小保镖",emoji:"\uD83D\uDEE1️",slogan:"小小的身体，大大的忠诚。",description:"这是一只让人心疼又感动的毛孩子！它内向敏感，对这个世界保持着一份小心翼翼；它憨厚老实，不懂什么心机，只知道全心全意爱你。虽然它对外人友善但保持距离，但对你，它会拼尽全力保护。它是那种会因为你的一句话开心一整天，也会因为你的一点点忽视而失落的小可爱。",traits:["\uD83C\uDF80 敏感细腻: 能感知你的情绪变化","\uD83D\uDEE1️ 护主心切: 虽然内向，但保护你时很勇敢","\uD83D\uDC3B 憨厚忠诚: 认准了你，这辈子就你了","⚡ 活力藏不住: 在熟悉的人面前很活泼"],tips:["温柔对待: 敏感的它经不起严厉批评","稳定陪伴: 多陪它，给它安全感","循序渐进: 不要突然改变环境或 routine","积极强化: 鼓励比惩罚更有效","社交慢慢来: 不要强迫它社交，让它自己决定"],activities:["\uD83D\uDC91 和主人的专属时光","\uD83C\uDFE0 家庭小游戏","\uD83D\uDEB6 安静的散步"],quirks:["容易紧张，需要更多安全感","太敏感，可能会因为小事受惊"],color:"#9B59B6"},{code:"ISFA",name:"安静美男子",emoji:"\uD83C\uDFA8",slogan:"岁月静好，与你相伴。",description:"这是一只自带优雅气质的毛孩子！它不喜欢吵闹，不喜欢争抢，只是静静地、优雅地存在于你的生活中。它聪明懂事，知道什么时候该安静，什么时候可以撒个娇。它慵懒却不失风度，内向却不冷漠。和它在一起，你会感觉时间都慢了下来，生活变得温柔而美好。",traits:["\uD83E\uDDA2 优雅内敛: 做什么都从容不迫","\uD83E\uDDE0 懂事聪明: 不需要多说，它都懂","\uD83D\uDECB️ 懒洋洋: 最爱的事情是躺在你身边","\uD83D\uDC99 温柔友善: 虽然不热情，但对谁都温和"],tips:["安静环境: 它不喜欢吵闹，给它一个宁静的家","尊重独处: 内向的它需要自己的空间","脑力游戏: 聪明但懒，适合动脑的游戏","温和互动: 它更喜欢安静的陪伴","注意饮食: 慵懒体质容易胖"],activities:["\uD83D\uDECB️ 沙发依偎","\uD83D\uDCDA 安静的阅读时光（它陪你）","\uD83E\uDDE9 慢节奏游戏"],quirks:["太安静，有时候你会忘记它的存在","对陌生人太冷淡，可能需要很久才能熟络"],color:"#95A5A6"},{code:"ISFG",name:"高冷独行侠",emoji:"\uD83D\uDC3A",slogan:"独来独往，但心里有你。",description:"这是一只有点神秘又特别酷的毛孩子！它独来独往、不喜热闹，像个独行侠一样有自己的世界。它憨厚老实，没有什么心眼，只是单纯地按照自己的方式生活。它不需要太多关注，也不需要太多互动，但当你需要它的时候，它总会在那里。它是那种让你学会尊重个体差异、欣赏独处之美的存在。",traits:["\uD83C\uDF19 高冷神秘: 不爱凑热闹，独来独往","\uD83D\uDC3B 憨厚真诚: 虽然高冷，但对你很真心","\uD83D\uDECB️ 超级慵懒: 能不动就不动，静止就是艺术","\uD83D\uDC99 友善边界感: 对人和善，但保持距离"],tips:["尊重独立: 不要强迫它亲近或社交","低压力环境: 它喜欢简单、安静的生活","耐心等待: 建立信任需要时间，但值得","适度陪伴: 不需要一直互动，偶尔陪陪就好","注意健康: 慵懒要注意体重和关节"],activities:["\uD83C\uDFE0 独自休息","\uD83D\uDEB6 安静的短距离散步","\uD83C\uDF3F 自然的独处时光"],quirks:["太高冷，新主人可能会觉得它是不是不喜欢我","太懒，需要主人督促运动"],color:"#566573"},{code:"IITA",name:"佛系躺平狗",emoji:"\uD83E\uDDD8",slogan:"该吃吃该睡睡，凡事别往心里去。",description:"这是一只活得很通透的毛孩子！它内向却活跃，只是在自己的小世界里自得其乐；它聪明却不钻营，只是安静地观察着这个世界。它对陌生人保持警惕，但不是为了攻击，只是为了保护自己。它是那种会让你反思其实狗生也可以很简单的存在——有吃的、有睡的、有主人，就够了。",traits:["\uD83E\uDDD8 佛系: 不争不抢，随遇而安","\uD83E\uDDE0 聪明通透: 什么都懂，但懒得计较","⚡ 独处活跃: 自己玩也能玩得很开心","\uD83D\uDC41️ 警惕自保: 对危险有判断，懂得保护自己"],tips:["给它空间: 它喜欢自己待着，不要打扰","自娱自乐: 准备玩具，让它自己玩","渐进社交: 警惕性高，慢慢接触新事物","脑力刺激: 聪明需要动脑，给它益智玩具","适度互动: 虽然独立，但也需要你的关注"],activities:["\uD83C\uDFAF 独自玩玩具","\uD83E\uDDE9 益智游戏","\uD83C\uDFE0 居家自由活动"],quirks:["太独立，有时候会显得不需要你","对陌生人太警惕，可能会叫"],color:"#7F8C8D"},{code:"IITG",name:"社恐思想家",emoji:"\uD83E\uDD14",slogan:"想很多，动很少，但爱不少。",description:"这是一只内心世界很丰富的毛孩子！它内向社恐，不喜欢复杂的社交场合；它憨厚老实，有时候会想很多却不知道怎么表达。它活跃在自己的小天地里，对外界保持着一份警惕。它可能不是那种会热情迎接你的狗狗，但它会用自己的方式爱你——可能是默默地躺在你脚边，可能是远远地望着你，眼神里全是温柔。",traits:["\uD83E\uDD2F 想太多: 对外界刺激反应大，容易紧张","\uD83D\uDC3B 憨厚可爱: 单纯善良，没有坏心思","\uD83C\uDFC3 窝里活跃: 在安全环境很活泼","\uD83D\uDEE1️ 自我保护: 警惕是为了保护自己"],tips:["营造安全感: 给它一个可以躲藏的安全角落","不要强迫: 不要逼它做不想做的事","稳定routine: 规律的生活让它安心","温柔陪伴: 安静的陪伴比互动更重要","慢慢脱敏: 对害怕的事物要慢慢接触"],activities:["\uD83C\uDFE0 居家安全游戏","\uD83E\uDDD8 安静的陪伴时光","\uD83D\uDEB6 无人的清晨散步"],quirks:["容易紧张焦虑，需要更多耐心","社交能力弱，不适合热闹场合"],color:"#2C3E50"},{code:"IIFA",name:"软萌棉花糖",emoji:"☁️",slogan:"软糯可爱，只想被你宠爱。",description:"这是一只让人想捧在手心的毛孩子！它软糯可爱、内向乖巧，像个棉花糖一样柔软。它聪明懂事，虽然对陌生人保持警惕，但对你是百分百的信任和依赖。它慵懒不爱动，最喜欢的事情就是被你抱着、被你摸摸。它是那种会让你母性/父性大爆发、想要好好保护的存在。",traits:["☁️ 软糯可爱: 像个毛绒玩具，让人想抱","\uD83E\uDDE0 懂事聪明: 知道怎么讨你欢心","\uD83D\uDECB️ 懒懒的: 抱在怀里就能睡一天","\uD83D\uDC40 cautious: 对陌生环境小心翼翼"],tips:["多抱抱它: 它最需要的就是你的怀抱","温柔对待: 软萌的它受不得一点惊吓","安全环境: 警惕让它需要熟悉、安全的环境","脑力游戏: 聪明但懒，动脑比动身好","饮食控制: 慵懒容易胖，注意体重"],activities:["\uD83E\uDD17 抱抱 time","\uD83D\uDECB️ 怀里睡觉","\uD83E\uDDE9 轻度脑力游戏"],quirks:["太依赖你，离开你会有点焦虑","太懒，需要督促运动"],color:"#D7BDE2"},{code:"IIFG",name:"神秘隐士",emoji:"\uD83C\uDF19",slogan:"远离喧嚣，独守一方宁静。",description:"这是一只仿佛不属于这个喧嚣世界的毛孩子！它极度内向、极度慵懒，总是躲在角落静静地观察着一切。它憨厚老实，没有什么欲望，只是简单地活着。它对世界保持着距离，不是因为冷漠，而是因为敏感。它是那种会让你学会慢下来、学会独处、学会欣赏安静之美的存在。",traits:["\uD83C\uDF19 神秘安静: 像一个月亮下的影子","\uD83D\uDC3B 憨厚无争: 什么都不争，随遇而安","\uD83D\uDECB️ 能不动就不动: 静止是常态","\uD83D\uDC41️ 高度警惕: 对环境变化很敏感"],tips:["绝对尊重: 它不需要被改变，只需要被接纳","安静环境: 吵闹会让它很焦虑","安全角落: 给它一个可以躲的地方","耐心陪伴: 建立信任需要很长时间","简单生活: 不要复杂化它的生活"],activities:["\uD83C\uDF3F 自然的独处","\uD83C\uDFE0 安静的休息","\uD83D\uDCA4 睡觉（它最擅长的）"],quirks:["太慢热，新主人可能会觉得很难亲近","太懒，需要注意健康问题"],color:"#8E44AD"}];function t(D){let u=[{key:"extraversion",score:D.extraversion,positive:"E",negative:"I"},{key:"stability",score:D.stability,positive:"S",negative:"N"},{key:"trainability",score:D.trainability,positive:"T",negative:"F"},{key:"activity",score:D.activity,positive:"A",negative:"C"},{key:"friendliness",score:D.friendliness,positive:"F",negative:"G"}].sort((D,u)=>Math.abs(u.score)-Math.abs(D.score)),i=u[0],t=u[1],s=i.score>=0?i.positive:i.negative,o=t.score>=0?t.positive:t.negative,E=u[2],r=E.score>=0?E.positive:E.negative,a=s+o+r+"A",C=e.find(D=>D.code===a);if(C)return C;let c={EST:"ESTA",EIT:"EITG",ESF:"ESFA",EIF:"EIFA",IST:"ISTG",IIT:"IITG",ISF:"ISFG",IIF:"IIFG",EIA:"EITA",EIC:"EITG",IIA:"IITA",IIC:"IIFG",ISA:"ISTA",ISC:"ISTG"},n=c[s+o+r]||c[s+o]||"ESTA";return e.find(D=>D.code===n)||e[0]}}}]);